insert into public.exercises(
  id, source, source_id, name, slug, primary_muscle, secondary_muscles, equipment, difficulty,
  mechanics, movement_pattern, force_type, instructions, is_approved, is_global
) values
  ('3eab8f04-2b5f-5c5e-9fed-41c63b90d45b', 'plaivra_curated', 'plaivra_curated:v1:barbell-bench-press', 'Barbell Bench Press', 'barbell-bench-press', 'pectoralis_major', array['anterior_deltoid']::text[], array['barbell', 'bench']::text[], 'intermediate', 'compound', 'horizontal_push', 'push', '[{"order":1,"text":"Lie on a flat bench with feet planted and shoulder blades set."},{"order":2,"text":"Grip the bar slightly wider than shoulder width."},{"order":3,"text":"Lower the bar under control toward the mid-chest."},{"order":4,"text":"Press the bar upward while maintaining the same torso position."}]', true, true),
  ('1ee4a77a-0f7a-5fad-b281-52a191a2a685', 'plaivra_curated', 'plaivra_curated:v1:incline-dumbbell-bench-press', 'Incline Dumbbell Bench Press', 'incline-dumbbell-bench-press', 'pectoralis_major', array['triceps_brachii']::text[], array['dumbbells', 'incline_bench']::text[], 'intermediate', 'compound', 'inclined_horizontal_push', 'push', '[{"order":1,"text":"Set the bench to a moderate incline and sit with a dumbbell in each hand."},{"order":2,"text":"Position the dumbbells beside the upper chest with wrists stacked."},{"order":3,"text":"Press upward without allowing the shoulders to shrug."},{"order":4,"text":"Lower under control to the starting position."}]', true, true),
  ('465595ee-bd17-598d-80f3-ac0990a1d8d1', 'plaivra_curated', 'plaivra_curated:v1:push-up', 'Push-Up', 'push-up', 'pectoralis_major', array['anterior_deltoid', 'serratus_anterior']::text[], array['bodyweight']::text[], 'beginner', 'compound', 'horizontal_push', 'push', '[{"order":1,"text":"Place the hands slightly wider than shoulder width and form a straight body line."},{"order":2,"text":"Brace the trunk and lower the chest between the hands."},{"order":3,"text":"Keep the elbows in a controlled angle rather than flaring fully."},{"order":4,"text":"Press the floor away to return to the top."}]', true, true),
  ('98764e63-6df7-5a6f-8db7-727ea8088407', 'plaivra_curated', 'plaivra_curated:v1:parallel-bar-chest-dip', 'Parallel-Bar Chest Dip', 'parallel-bar-chest-dip', 'pectoralis_major', array['anterior_deltoid']::text[], array['parallel_bars', 'bodyweight']::text[], 'intermediate', 'compound', 'vertical_push', 'push', '[{"order":1,"text":"Support the body on parallel bars with the torso slightly inclined."},{"order":2,"text":"Lower under control while the shoulders remain stable."},{"order":3,"text":"Descend only through a comfortable shoulder range."},{"order":4,"text":"Press through the bars to return to support."}]', true, true),
  ('f29c4aec-5ab2-5ff5-bb62-1c1ff20b1f3b', 'plaivra_curated', 'plaivra_curated:v1:standing-cable-chest-fly', 'Standing Cable Chest Fly', 'standing-cable-chest-fly', 'pectoralis_major', array['anterior_deltoid']::text[], array['cable_machine']::text[], 'beginner', 'isolation', 'horizontal_adduction', 'pull', '[{"order":1,"text":"Set the cable handles near chest height and take a staggered stance."},{"order":2,"text":"Begin with the arms open and elbows slightly bent."},{"order":3,"text":"Bring the hands together through horizontal adduction."},{"order":4,"text":"Return slowly without losing trunk position."}]', true, true),
  ('6ceb57a2-f7e1-5c2b-b76b-97dbeee6b104', 'plaivra_curated', 'plaivra_curated:v1:pec-deck-fly', 'Pec Deck Fly', 'pec-deck-fly', 'pectoralis_major', array['anterior_deltoid']::text[], array['pec_deck_machine']::text[], 'beginner', 'isolation', 'horizontal_adduction', 'push', '[{"order":1,"text":"Adjust the seat so the handles align with the chest."},{"order":2,"text":"Keep the back supported and elbows softly bent."},{"order":3,"text":"Bring the arms together without shrugging."},{"order":4,"text":"Return until a controlled chest stretch is reached."}]', true, true),
  ('9c5bdecd-8875-5bc0-8333-f3303c381bb5', 'plaivra_curated', 'plaivra_curated:v1:standing-barbell-overhead-press', 'Standing Barbell Overhead Press', 'standing-barbell-overhead-press', 'anterior_deltoid', array['lateral_deltoid', 'trapezius', 'serratus_anterior']::text[], array['barbell']::text[], 'intermediate', 'compound', 'vertical_push', 'push', '[{"order":1,"text":"Stand with the bar at upper-chest height and brace the trunk."},{"order":2,"text":"Press the bar vertically while moving the head clear of the bar path."},{"order":3,"text":"Finish with the bar balanced over the shoulders."},{"order":4,"text":"Lower under control to the upper chest."}]', true, true),
  ('ccecf045-a142-5c12-a08c-be20fa267d0f', 'plaivra_curated', 'plaivra_curated:v1:seated-dumbbell-shoulder-press', 'Seated Dumbbell Shoulder Press', 'seated-dumbbell-shoulder-press', 'anterior_deltoid', array['lateral_deltoid', 'trapezius']::text[], array['dumbbells', 'bench']::text[], 'beginner', 'compound', 'vertical_push', 'push', '[{"order":1,"text":"Sit against a stable bench with dumbbells at shoulder height."},{"order":2,"text":"Brace the trunk and keep wrists stacked over elbows."},{"order":3,"text":"Press upward without excessive lumbar extension."},{"order":4,"text":"Lower the dumbbells under control."}]', true, true),
  ('34a44fb5-76f0-5517-837a-27ba97df9c20', 'plaivra_curated', 'plaivra_curated:v1:dumbbell-lateral-raise', 'Dumbbell Lateral Raise', 'dumbbell-lateral-raise', 'lateral_deltoid', array['anterior_deltoid', 'trapezius']::text[], array['dumbbells']::text[], 'beginner', 'isolation', 'shoulder_abduction', 'pull', '[{"order":1,"text":"Stand tall with dumbbells beside the body and elbows softly bent."},{"order":2,"text":"Raise the arms in the scapular plane toward shoulder height."},{"order":3,"text":"Avoid momentum and excessive shrugging."},{"order":4,"text":"Lower slowly to the starting position."}]', true, true),
  ('a0875e46-0f47-5f81-9dd8-addf4e4eb240', 'plaivra_curated', 'plaivra_curated:v1:reverse-pec-deck-fly', 'Reverse Pec Deck Fly', 'reverse-pec-deck-fly', 'posterior_deltoid', array['lateral_deltoid', 'upper_back', 'rotator_cuff']::text[], array['reverse_pec_deck_machine']::text[], 'beginner', 'isolation', 'horizontal_abduction', 'pull', '[{"order":1,"text":"Adjust the seat so the chest is supported and handles align with the shoulders."},{"order":2,"text":"Move the arms outward through horizontal abduction."},{"order":3,"text":"Keep the torso still and avoid shrugging."},{"order":4,"text":"Return under control."}]', true, true),
  ('9ab20fb0-f34c-55cc-afd9-530f9ddcee29', 'plaivra_curated', 'plaivra_curated:v1:cable-face-pull', 'Cable Face Pull', 'cable-face-pull', 'posterior_deltoid', array['trapezius', 'rotator_cuff']::text[], array['cable_machine', 'rope_attachment']::text[], 'beginner', 'compound', 'horizontal_pull_external_rotation', 'pull', '[{"order":1,"text":"Set a rope attachment around upper-chest or face height."},{"order":2,"text":"Pull the rope toward the face while separating the ends."},{"order":3,"text":"Finish with the elbows high and shoulders externally rotated."},{"order":4,"text":"Return under control without losing trunk position."}]', true, true),
