  ('62583748-ed3e-56fb-9245-bc1358cd3f1c', 'plaivra_curated', 'plaivra_curated:v1:seated-calf-raise', 'Seated Calf Raise', 'seated-calf-raise', 'soleus', array['gastrocnemius']::text[], array['seated_calf_raise_machine']::text[], 'beginner', 'isolation', 'plantar_flexion_flexed_knee', 'push', '[{"order":1,"text":"Sit with the knees bent and the load secured over the thighs."},{"order":2,"text":"Lower the heels through a comfortable range."},{"order":3,"text":"Press through the forefoot to raise the heels."},{"order":4,"text":"Lower under control."}]', true, true),
  ('ba09e746-1f7b-5eab-91e9-e1314cd16831', 'plaivra_curated', 'plaivra_curated:v1:tibialis-raise', 'Tibialis Raise', 'tibialis-raise', 'tibialis_anterior', '{}'::text[], array['bodyweight']::text[], 'beginner', 'isolation', 'dorsiflexion', 'pull', '[{"order":1,"text":"Stand with the heels planted and the body supported as needed."},{"order":2,"text":"Lift the forefoot by dorsiflexing the ankles."},{"order":3,"text":"Pause briefly at the top."},{"order":4,"text":"Lower the forefoot under control."}]', true, true),
  ('4112990b-6d87-52e8-b9c8-81f65c7a1a0e', 'plaivra_curated', 'plaivra_curated:v1:front-plank', 'Front Plank', 'front-plank', 'rectus_abdominis', array['obliques']::text[], array['bodyweight']::text[], 'beginner', 'isometric', 'anti_extension', 'isometric', '[{"order":1,"text":"Place the forearms on the floor with elbows below the shoulders."},{"order":2,"text":"Extend the legs and form a straight body line."},{"order":3,"text":"Brace the abdomen and glutes without holding the breath."},{"order":4,"text":"Maintain the position for the planned duration."}]', true, true),
  ('b629a999-2218-59fd-8fdb-a9dbf305f93b', 'plaivra_curated', 'plaivra_curated:v1:side-plank', 'Side Plank', 'side-plank', 'obliques', array['rectus_abdominis', 'gluteus_medius']::text[], array['bodyweight']::text[], 'beginner', 'isometric', 'anti_lateral_flexion', 'isometric', '[{"order":1,"text":"Support the body on one forearm with the elbow below the shoulder."},{"order":2,"text":"Stack or stagger the feet and lift the hips."},{"order":3,"text":"Maintain a straight line while resisting side bending."},{"order":4,"text":"Hold for the planned duration, then repeat on the other side."}]', true, true),
  ('1cee817a-9735-5d5f-9c63-882b9faac72c', 'plaivra_curated', 'plaivra_curated:v1:cable-crunch', 'Cable Crunch', 'cable-crunch', 'rectus_abdominis', array['obliques']::text[], array['cable_machine', 'rope_attachment']::text[], 'beginner', 'isolation', 'trunk_flexion', 'pull', '[{"order":1,"text":"Kneel facing a high cable with the rope near the head."},{"order":2,"text":"Flex the trunk by bringing the ribs toward the pelvis."},{"order":3,"text":"Keep the hips relatively stable."},{"order":4,"text":"Return under control."}]', true, true),
  ('0881fc74-be9e-562b-98ae-87099e9cee1d', 'plaivra_curated', 'plaivra_curated:v1:reverse-crunch', 'Reverse Crunch', 'reverse-crunch', 'rectus_abdominis', array['hip_flexors']::text[], array['bodyweight']::text[], 'beginner', 'isolation', 'trunk_flexion_posterior_pelvic_tilt', 'pull', '[{"order":1,"text":"Lie on the back with hips and knees flexed."},{"order":2,"text":"Use the abdomen to posteriorly tilt the pelvis and lift the hips slightly."},{"order":3,"text":"Avoid swinging the legs for momentum."},{"order":4,"text":"Lower the pelvis under control."}]', true, true),
  ('66a68929-cbce-54fc-a7e0-d97e1ba46a97', 'plaivra_curated', 'plaivra_curated:v1:hanging-knee-raise', 'Hanging Knee Raise', 'hanging-knee-raise', 'rectus_abdominis', array['forearms', 'obliques']::text[], array['pull_up_bar', 'bodyweight']::text[], 'intermediate', 'compound', 'hip_flexion_trunk_control', 'pull', '[{"order":1,"text":"Hang from a stable bar with the shoulders controlled."},{"order":2,"text":"Raise the knees toward the torso while controlling the pelvis."},{"order":3,"text":"Avoid swinging or using momentum."},{"order":4,"text":"Lower the legs under control."}]', true, true),
  ('c84fc6cb-818e-5957-91d0-89abe8efe239', 'plaivra_curated', 'plaivra_curated:v1:pallof-press', 'Pallof Press', 'pallof-press', 'obliques', array['rectus_abdominis']::text[], array['cable_machine']::text[], 'beginner', 'isometric', 'anti_rotation', 'isometric', '[{"order":1,"text":"Stand perpendicular to a cable with the handle at the chest."},{"order":2,"text":"Brace the trunk and press the handle straight forward."},{"order":3,"text":"Resist rotation toward the cable."},{"order":4,"text":"Return the handle to the chest under control."}]', true, true),
  ('245bde5b-cabb-51b2-8342-eaaec6dbf1b7', 'plaivra_curated', 'plaivra_curated:v1:cable-wood-chop', 'Cable Wood Chop', 'cable-wood-chop', 'obliques', array['rectus_abdominis', 'erector_spinae']::text[], array['cable_machine']::text[], 'intermediate', 'compound', 'trunk_rotation', 'mixed', '[{"order":1,"text":"Stand beside a cable and establish a stable stance."},{"order":2,"text":"Move the handle diagonally across the body with coordinated trunk and hip motion."},{"order":3,"text":"Keep the movement controlled rather than pulling only with the arms."},{"order":4,"text":"Return to the starting position under control."}]', true, true);

